#ifdef PLAY_SONGS_IN_ORDER

// Get a random song, but weight the selection based on how long
// it has been since each song has been played.
const note_t *get_random_song(int *tempo, const char **title)
{
  static int song_num = -1;
  
  song_num = (song_num + 1) % NUM_SONGS;
  *tempo = tempos[song_num] * 5 / 4; // speed it up by a factor of 5/4
  *title = titles[song_num];

  return songs[song_num];
}


#else

// Get a random song, but weight the selection based on how long
// it has been since each song has been played.
const note_t *get_random_song(int *tempo, const char **title)
{
  static int total_probability = NUM_SONGS * (NUM_SONGS-1);
  static int firstcall = 1;
  static int song_probability[NUM_SONGS];
  volatile uint32_t *mtime_lo = (volatile uint32_t *)configMTIME_BASE_ADDRESS;
  int song_num,selector,i,cur;
  if(firstcall)
    {
      for(i = 0; i<NUM_SONGS; i++)
        song_probability[i] = (NUM_SONGS-1);
      firstcall = 0;
      // First call: all songs have equal weight.  XOR rand() with
      // the live MTIME counter for extra entropy — by now the
      // scheduler and interrupts have been running, so MTIME has
      // accumulated real timing jitter.
      song_num = (rand() ^ *mtime_lo) % NUM_SONGS;
    }
  else
    {
      selector = (rand() ^ *mtime_lo) % total_probability;
      for(i=0,cur=song_probability[0];
          i<NUM_SONGS-1 && (cur <= selector || song_probability[i] < 1);
          i++,cur+=song_probability[i]);
      song_num = i;
    }
  for(i=0;i<NUM_SONGS;i++)
  {
    if(i == song_num)
    {
      total_probability -= song_probability[i];
      song_probability[i] = 0;
      }
    else
      song_probability[i]++;
  }
  total_probability += NUM_SONGS-1;

  *tempo = tempos[song_num] * 5 / 4; // speed it up by a factor of 5/4
  *title = titles[song_num];
  return songs[song_num];
}

#endif
